//! Cross-implementation conformance: our codec vs Nicotine+'s real output.
//!
//! The byte vectors in `fixtures/nicotine_vectors.rs` are generated by running
//! Nicotine+'s own message packers (see scripts/gen-nicotine-vectors.py). These
//! tests assert that our encoder produces the same bytes Nicotine+ does, and
//! that our decoder accepts Nicotine+'s real SharedFileListResponse — making the
//! reference implementation the executed oracle, not a human reading of it.

use std::net::Ipv4Addr;

use soulseek_proto::frame::split_frame;
use soulseek_proto::peer::{ConnectionType, PeerInit, PierceFirewall};
use soulseek_proto::peer_message::{
    FolderContentsRequest, GetSharedFileList, PeerMessage, UserInfoRequest, UserInfoResponse,
};
use soulseek_proto::server::{
    AcceptChildren, BranchLevel, BranchRoot, ConnectToPeerRequest, FileSearchRequest,
    GetPeerAddressRequest, HaveNoParent, LoginRequest, LoginResponse, ServerMessage, ServerRequest,
    SetWaitPort,
};
use soulseek_proto::distributed::{
    DistribBranchLevel, DistribBranchRoot, DistribChildDepth, DistribEmbedded, DistribPing,
    DistribSearch,
};
use soulseek_proto::transfer::{
    FileOffset, FileTransferInit, PlaceInQueueRequest, PlaceInQueueResponse, QueueUpload,
    TransferDirection, TransferRequest, TransferResponse, UploadDenied, UploadFailed,
};
use soulseek_proto::Reader;

mod vectors {
    include!("fixtures/nicotine_vectors.rs");
}

fn body<M: ServerRequest>(message: &M) -> Vec<u8> {
    let mut buf = Vec::new();
    message.encode_body(&mut buf);
    buf
}

#[test]
fn login_body_matches_nicotine() {
    let ours = body(&LoginRequest {
        username: "alice".into(),
        password: "s3cr3t".into(),
        major_version: 160,
        minor_version: 1,
    });
    // Includes the MD5(username+password) digest string — proves we compute it
    // the same way Nicotine+ does.
    assert_eq!(ours, vectors::LOGIN_BODY);
}

