#[test]
fn set_wait_port_is_a_soulseekqt_superset_of_nicotine() {
    // We send the SoulseekQt form: port + obfuscation_type + obfuscated_port.
    // Nicotine+ sends the port ALONE (slskmessages.py: `__slots__ = ("port",)`),
    // so the executed-oracle fixture SET_WAIT_PORT_BODY is just the 4-byte port.
    // The server accepts both; Nicotine+'s bytes must be the prefix of ours.
    let ours = body(&SetWaitPort { port: 2234, obfuscation_type: 0, obfuscated_port: 0 });
    assert_eq!(&ours[..vectors::SET_WAIT_PORT_BODY.len()], vectors::SET_WAIT_PORT_BODY);
    assert_eq!(ours.len(), 12, "port + obfuscation_type + obfuscated_port");
}

#[test]
fn our_decoder_accepts_nicotines_shared_file_list() {
    // Nicotine+'s real, compressed SharedFileListResponse with one public and
    // one private folder. Decoding it exercises the public dirs, the unknown=0
    // field, and the private-dir list — the layout our codec previously got
    // wrong (it would have dropped the private shares).
    let (payload, rest) = split_frame(vectors::SHARED_FILE_LIST_FRAME).unwrap().unwrap();
    assert!(rest.is_empty());

    let PeerMessage::SharedFileList(resp) = PeerMessage::decode(payload).unwrap() else {
        panic!("expected a shared file list");
    };

    assert_eq!(resp.directories.len(), 1);
    assert_eq!(resp.directories[0].path, "Music\\Album");
    assert_eq!(resp.directories[0].files[0].name, "Music\\Album\\song.mp3");
    assert_eq!(resp.directories[0].files[0].size, 5_242_880);

    assert_eq!(resp.private_directories.len(), 1, "private shares must be decoded");
    assert_eq!(resp.private_directories[0].path, "Buddies");
    assert_eq!(resp.private_directories[0].files[0].name, "Buddies\\secret.flac");
    assert_eq!(resp.private_directories[0].files[0].size, 999);
}

